import React, { useState, useEffect } from 'react';
import { ActivityIndicator, View, StyleSheet } from 'react-native';
import { NavigationContainer } from '@react-navigation/native';
import AppNavigator from './src/navigation/AppNavigator';
import AuthService from './src/services/AuthService';

export default function App() {
  const [isLoading, setIsLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  useEffect(() => {
    const checkAuthStatus = async () => {
      try {
        const tokens = await AuthService.getTokens();
        if (tokens && tokens.accessToken) {
          // Attempt to refresh token to ensure it's valid
          try {
            await AuthService.getAccessToken(true); // Force refresh if expired
            setIsAuthenticated(true);
          } catch (refreshError) {
            console.warn("Failed to refresh token on app start, user will need to log in:", refreshError);
            setIsAuthenticated(false);
            await AuthService.clearTokens(); // Clear invalid tokens
          }
        } else {
          setIsAuthenticated(false);
        }
      } catch (error) {
        console.error("Error checking auth status:", error);
        setIsAuthenticated(false);
      } finally {
        setIsLoading(false);
      }
    };

    checkAuthStatus();
  }, []);

  if (isLoading) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#0000ff" />
      </View>
    );
  }

  return (
    <NavigationContainer>
      <AppNavigator isAuthenticated={isAuthenticated} onSetAuthenticated={setIsAuthenticated} />
    </NavigationContainer>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
  },
});

