// src/services/AuthService.js
import AsyncStorage from '@react-native-async-storage/async-storage';
import * as WebBrowser from 'expo-web-browser';
import * as Linking from 'expo-linking';
import { OAUTH_CONFIG } from '../config/oauth';
import { generatePkce } from '../utils/pkce'; // PKCE utility

const TOKEN_KEY = 'oauth_tokens';
const PKCE_VERIFIER_KEY = 'pkce_code_verifier';

class AuthService {
  constructor() {
    this.redirectListener = null;
    this.currentTokenPromise = null; // To prevent multiple refresh token calls
  }

  async storeTokens(tokens) {
    const now = Date.now();
    const expiresAt = now + (tokens.expires_in * 1000) - (60 * 1000); // 1 minute buffer
    const data = {
      accessToken: tokens.access_token,
      refreshToken: tokens.refresh_token,
      expiresAt: expiresAt,
      idToken: tokens.id_token, // If OpenID Connect is used
      scope: tokens.scope,
    };
    await AsyncStorage.setItem(TOKEN_KEY, JSON.stringify(data));
  }

  async getTokens() {
    const tokensString = await AsyncStorage.getItem(TOKEN_KEY);
    return tokensString ? JSON.parse(tokensString) : null;
  }

  async clearTokens() {
    await AsyncStorage.removeItem(TOKEN_KEY);
    await AsyncStorage.removeItem(PKCE_VERIFIER_KEY);
  }

  async login() {
    await this.clearTokens(); // Ensure no old tokens are present

    const { verifier, challenge } = generatePkce();
    await AsyncStorage.setItem(PKCE_VERIFIER_KEY, verifier);

    const authUrl = `${OAUTH_CONFIG.authorizationEndpoint}` +
      `?response_type=code` +
      `&client_id=${OAUTH_CONFIG.clientId}` +
      `&redirect_uri=${encodeURIComponent(OAUTH_CONFIG.redirectUri)}` +
      `&scope=${encodeURIComponent(OAUTH_CONFIG.scope)}` +
      `&code_challenge=${challenge}` +
      `&code_challenge_method=S256`;

    let result = null;
    try {
      result = await WebBrowser.openAuthSessionAsync(authUrl, OAUTH_CONFIG.redirectUri);
    } catch (e) {
      console.error("WebBrowser.openAuthSessionAsync error:", e);
      throw new Error("Failed to open browser for authentication.");
    }

    if (result.type === 'success' && result.url) {
      const url = new URL(result.url);
      const code = url.searchParams.get('code');
      if (code) {
        return this.exchangeCodeForToken(code);
      } else {
        throw new Error("Authorization code not found in redirect URL.");
      }
    } else if (result.type === 'cancel') {
      console.log("Authentication cancelled by user.");
      return false;
    } else if (result.type === 'dismiss') {
      console.log("Authentication dismissed by user.");
      return false;
    } else {
      throw new Error(`Authentication failed with type: ${result.type}`);
    }
  }

  async exchangeCodeForToken(code) {
    const verifier = await AsyncStorage.getItem(PKCE_VERIFIER_KEY);
    if (!verifier) {
      throw new Error("PKCE code verifier not found. Cannot exchange code.");
    }

    const requestBody = new URLSearchParams({
      grant_type: 'authorization_code',
      code: code,
      redirect_uri: OAUTH_CONFIG.redirectUri,
      client_id: OAUTH_CONFIG.clientId,
      code_verifier: verifier,
    });

    // Only include client_secret if it exists and is intended for this flow (as per user request)
    if (OAUTH_CONFIG.clientSecret) {
      requestBody.append('client_secret', OAUTH_CONFIG.clientSecret);
    }

    const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: requestBody.toString(),
    });

    if (!response.ok) {
      const errorData = await response.json();
      console.error("Token exchange failed:", errorData);
      throw new Error(errorData.error_description || errorData.error || "Failed to exchange code for token.");
    }

    const tokens = await response.json();
    await this.storeTokens(tokens);
    await AsyncStorage.removeItem(PKCE_VERIFIER_KEY); // PKCE verifier no longer needed
    return true;
  }

  async refreshToken() {
    if (this.currentTokenPromise) {
      return this.currentTokenPromise; // Return existing promise if a refresh is already in progress
    }

    this.currentTokenPromise = (async () => {
      const storedTokens = await this.getTokens();
      if (!storedTokens || !storedTokens.refreshToken) {
        throw new Error("No refresh token available. User must re-authenticate.");
      }

      console.log("Attempting to refresh token...");

      const requestBody = new URLSearchParams({
        grant_type: 'refresh_token',
        refresh_token: storedTokens.refreshToken,
        client_id: OAUTH_CONFIG.clientId,
        scope: OAUTH_CONFIG.scope,
      });

      // Only include client_secret if it exists and is intended for this flow
      if (OAUTH_CONFIG.clientSecret) {
        requestBody.append('client_secret', OAUTH_CONFIG.clientSecret);
      }

      try {
        const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
          },
          body: requestBody.toString(),
        });

        if (!response.ok) {
          const errorData = await response.json();
          console.error("Token refresh failed:", errorData);
          await this.clearTokens(); // Clear all tokens on refresh failure
          throw new Error(errorData.error_description || errorData.error || "Failed to refresh token.");
        }

        const newTokens = await response.json();
        // The OAuth server might not return a new refresh token. Use the old one if not.
        const mergedTokens = { ...storedTokens, ...newTokens };
        mergedTokens.refresh_token = newTokens.refresh_token || storedTokens.refreshToken;
        await this.storeTokens(mergedTokens);
        console.log("Token refreshed successfully.");
        return mergedTokens.accessToken;
      } finally {
        this.currentTokenPromise = null; // Clear the promise when done
      }
    })();
    return this.currentTokenPromise;
  }

  async getAccessToken(forceRefresh = false) {
    const storedTokens = await this.getTokens();

    if (!storedTokens || !storedTokens.accessToken) {
      return null; // No tokens, user needs to login
    }

    const now = Date.now();
    if (forceRefresh || now >= storedTokens.expiresAt) {
      console.log("Access token expired or force refresh. Attempting to refresh.");
      try {
        return await this.refreshToken();
      } catch (error) {
        console.error("Failed to get fresh access token:", error);
        await this.clearTokens(); // Ensure user is logged out if refresh fails
        return null;
      }
    }
    return storedTokens.accessToken;
  }

  async logout() {
    await this.clearTokens();
    console.log("User logged out.");
    // Optionally, perform an OAuth logout redirect if your server supports it
    // Example: WebBrowser.openBrowserAsync(`${OAUTH_CONFIG.logoutEndpoint}?client_id=${OAUTH_CONFIG.clientId}&post_logout_redirect_uri=${encodeURIComponent(OAUTH_CONFIG.redirectUri)}`);
  }
}

export default new AuthService();

// src/utils/pkce.js
import 'react-native-get-random-values'; // Polyfill for crypto.getRandomValues
import { randomBytes } from 'crypto';
import { sha256 } from 'js-sha256';
import { encode } from 'base-64';

// Generates a cryptographically random string for the code_verifier
const generateRandomString = (length) => {
  const characters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~';
  let result = '';
  // Use crypto.getRandomValues for true randomness
  const randomValues = randomBytes(length);
  for (let i = 0; i < length; i++) {
    result += characters[randomValues[i] % characters.length];
  }
  return result;
};

// Base64Url-encodes a string
const base64UrlEncode = (str) => {
  return encode(str)
    .replace(/\+/g, '-') // Replace + with -
    .replace(/\//g, '_') // Replace / with _
    .replace(/=+$/, ''); // Remove = at the end
};

// Generates PKCE code_verifier and code_challenge
export const generatePkce = () => {
  const verifier = generateRandomString(128); // Length between 43 and 128 characters
  const challenge = base64UrlEncode(sha256(verifier)); // SHA256 hash, then Base64Url encode
  return { verifier, challenge };
};

